    addCountyBoundary(map) {
      // 宜川县县域轮廓坐标点（简化示例）
      const countyPath = [
        [110.05, 35.95],
        [110.08, 36.12],
        [110.25, 36.15],
        [110.30, 36.05],
        [110.28, 35.92],
        [110.15, 35.90],
        [110.05, 35.95]
      ];
      
      // 创建县域轮廓多边形
      const countyPolygon = new AMap.Polygon({
        path: countyPath,
        strokeColor: "#FFA500", // 橙色轮廓线
        strokeWeight: 3,
        fillColor: "transparent",
        zIndex: 10
      });
      
      map.add(countyPolygon);
      
      // 添加主要河流（示例）
      const riverPath = [
        [110.10, 36.05],
        [110.15, 36.03],
        [110.20, 36.02],
        [110.25, 36.00]
      ];
      
      const riverPolyline = new AMap.Polyline({
        path: riverPath,
        strokeColor: "#00BFFF", // 蓝色河流
        strokeWeight: 4,
        zIndex: 20
      });
      
      map.add(riverPolyline);
      
      // 添加水库标记（示例）
      const reservoirMarker = new AMap.Marker({
        position: [110.18, 36.01],
        title: "东风水库",
        label: {
          content: "东风水库",
          offset: new AMap.Pixel(-15, 15)
        }
      });
      
      map.add(reservoirMarker);
      
      // 添加乡镇名称标记（示例）
      const townNames = [
        { position: [110.12, 36.08], name: "城关镇" },
        { position: [110.20, 36.10], name: "英旺乡" },
        { position: [110.15, 35.95], name: "云岩镇" }
      ];
      
      townNames.forEach(town => {
        const townLabel = new AMap.Text({
          text: town.name,
          position: town.position,
          style: {
            'padding': '.25rem .5rem',
            'background-color': 'rgba(255, 165, 0, 0.8)',
            'color': '#fff',
            'font-size': '12px',
            'border-radius': '4px'
          }
        });
        
        map.add(townLabel);
      });
    },
    
