    closeSettingsModal() {
      this.isSettingsModalVisible = false;
      this.inputUrl = '';
    },
    
    // 确认URL设置
    confirmUrl() {
      if (this.inputUrl && this.isValidUrl(this.inputUrl)) {
        this.weatherChartUrl = this.inputUrl;
        this.closeSettingsModal();
      } else {
        alert('请输入有效的URL地址');
      }
    },
    
    // 验证URL有效性
    isValidUrl(string) {
      try {
        new URL(string);
        return true;
      } catch (_) {
        return false;
      }
    }
  },
  
  beforeUnmount() {
